import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import axios from 'axios';
import './AdminDashboard.css'; // Import the CSS file

const AdminDashboard = () => {
  const { user } = useAuth();
  const [activeTab, setActiveTab] = useState('posts');
  const [posts, setPosts] = useState([]);
  const [newTitle, setNewTitle] = useState('');
  const [error, setError] = useState('');

  // 1. Kunin ang lahat ng posts pagka-load ng page
  useEffect(() => {
    const fetchPosts = async () => {
      try {
        const response = await axios.get('http://localhost:5000/api/posts');
        setPosts(response.data);
      } catch (err) {
        console.error("Error fetching posts:", err);
      }
    };
    fetchPosts();
  }, []);

  // 2. Logic para sa Pag-Post (Dito natin ilalagay ang TOKEN)
  const handleAddPost = async (e) => {
    e.preventDefault();
    setError('');

    const token = localStorage.getItem('token'); // Kunin ang token

    try {
      const config = {
        headers: {
          Authorization: `Bearer ${token}`, // <--- Eto ang solusyon sa "No token" error
        },
      };

      const postData = {
        title: newTitle,
        content: "Sample content from admin", // Pwede mong dagdagan ng content field kung gusto mo
      };

      const response = await axios.post('http://localhost:5000/api/posts', postData, config);
      
      // I-update ang table gamit ang bagong post mula sa database
      setPosts([response.data, ...posts]);
      setNewTitle('');
      alert('Post added successfully!');
    } catch (err) {
      setError(err.response?.data?.message || 'Not authorized to post.');
    }
  };

  const handleRemovePost = async (id) => {
    if (!window.confirm('Remove this post?')) return;
    
    const token = localStorage.getItem('token');
    try {
      await axios.delete(`http://localhost:5000/api/posts/${id}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setPosts(posts.filter(p => p._id !== id));
    } catch (err) {
      alert("Failed to delete post.");
    }
  };

  return (
    <div className="admin-dashboard-container">
      <div className="admin-card">
        <div className="admin-header">
          <h1 className="admin-title">Admin Dashboard</h1>
          <p className="admin-subtitle">Manage your content with ease</p>
        </div>
        
        <div className="admin-content">
          <div className="tab-navigation">
            <button 
              onClick={() => setActiveTab('posts')} 
              className={`tab-button ${activeTab === 'posts' ? 'active' : ''}`}
            >
              All Posts ({posts.length})
            </button>
          </div>

          {error && <div className="error-message">{error}</div>}

          <form onSubmit={handleAddPost} className="add-post-form">
            <input 
              type="text" 
              placeholder="Write a new post title..." 
              value={newTitle}
              onChange={(e) => setNewTitle(e.target.value)}
              className="post-input"
            />
            <button type="submit" className="submit-button">
              Post
            </button>
          </form>

          <div className="posts-table-container">
            <table className="posts-table">
              <thead>
                <tr>
                  <th>TITLE</th>
                  <th>STATUS</th>
                  <th>ACTION</th>
                </tr>
              </thead>
              <tbody>
                {posts.length > 0 ? (
                  posts.map(post => (
                    <tr key={post._id || post.id}>
                      <td>{post.title}</td>
                      <td>
                        <span className="status-badge">PUBLISHED</span>
                      </td>
                      <td>
                        <button 
                          onClick={() => handleRemovePost(post._id || post.id)} 
                          className="remove-button"
                        >
                          Remove
                        </button>
                      </td>
                    </tr>
                  ))
                ) : (
                  <tr>
                    <td colSpan="3" className="empty-state">
                      <div className="empty-state-icon">📝</div>
                      <p className="empty-state-text">No posts yet. Create your first post above!</p>
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;
